//! Auto-generated Unicode Nl/No numeric value lookup table.
//! Generated from Unicode character database. 1092 entries.
//! Characters already in hardcoded tables (builtins/unicode.rs) are excluded.

/// Look up the rational numeric value (numerator, denominator) for a Unicode
/// Nl (Number, Letter) or No (Number, Other) character by binary search.
pub(crate) fn lookup_nl_no_value(c: char) -> Option<(i64, i64)> {
    let cp = c as u32;
    TABLE
        .binary_search_by_key(&cp, |&(codepoint, _, _)| codepoint)
        .ok()
        .map(|i| (TABLE[i].1, TABLE[i].2))
}

