/// Look up the numeric value for a Unicode Lo (Letter, Other) character
/// that has a kAccountingNumeric, kOtherNumeric, or kPrimaryNumeric value
/// in the Unihan database. Returns (numerator, 1) for integer values.
pub(crate) fn lookup_lo_value(c: char) -> Option<(i64, i64)> {
    let cp = c as u32;
    LO_TABLE
        .binary_search_by_key(&cp, |&(codepoint, _, _)| codepoint)
        .ok()
        .map(|i| (LO_TABLE[i].1, LO_TABLE[i].2))
}

